mapper.select:
select id, title, product_type, price, status
from products


        AND title like concat('%',#{title},'%')


        AND product_type = #{productType}


        AND status = #{status}


order by id

mapper.update:
update products
title = #{title}, product_type = #{productType} , price = #{price}, status = #{status}, update_id = #{updateId}, update_time = #{updateTime}
where id = #{id}
